// In-memory product store — simulates a database that an ERP/PIM sync updates.
let products = [
  { id: 1, name: 'Laptop', price: 999, inventory: 50 },
  { id: 2, name: 'Phone', price: 699, inventory: 120 },
  { id: 3, name: 'Tablet', price: 499, inventory: 75 },
  { id: 4, name: 'Headphones', price: 199, inventory: 200 },
  { id: 5, name: 'Watch', price: 299, inventory: 30 }
];

let syncCount = 0;

/**
 * Return a snapshot of the current catalog data.
 * In production this would query PostgreSQL / MySQL / etc.
 */
export async function getAllProducts() {
  // Simulate database round-trip latency
  await new Promise(resolve => setTimeout(resolve, 100));
  return products.map(p => ({ ...p }));
}

/**
 * Simulate an upstream ERP/PIM sync that refreshes pricing and inventory.
 * In production this would call an external API, transform the response,
 * and upsert into the database.
 *
 * The operation is intentionally slow (3 s) so the caching / background
 * invalidation behaviour is observable during development.
 */
export async function syncCatalog() {
  // Simulate network + processing delay of a real batch sync
  await new Promise(resolve => setTimeout(resolve, 3_000));

  syncCount++;

  // Simulate new data arriving from an upstream system
  products = products.map(p => ({
    ...p,
    price: Math.round(p.price * (0.9 + Math.random() * 0.2)),   // ±10 %
    inventory: Math.max(0, p.inventory + Math.floor(Math.random() * 40) - 10)
  }));

  return {
    syncedAt: new Date().toISOString(),
    updatedCount: products.length,
    syncNumber: syncCount
  };
}

import { unstable_cache } from 'next/cache';
import { revalidateTag } from 'next/cache';
import { waitUntil } from 'next/server';
import { getAllProducts, syncCatalog } from '@/lib/db';

/* ------------------------------------------------------------------ */
/*  Cache the product list under the "products" tag so that every     */
/*  consumer of catalog data shares a single cache entry.  Sync can   */
/*  invalidate all of them at once via  revalidateTag("products") .   */
/* ------------------------------------------------------------------ */
const getCachedProducts = unstable_cache(
  async () => {
    console.log('[cache miss] fetching products from DB');
    return getAllProducts();
  },
  ['products-list'],                      // cache key parts
  { tags: ['products'], revalidate: false } // manual revalidation only
);

export default async function AdminProductsPage() {
  const products = await getCachedProducts();

  /* ---------------------------------------------------------------- */
  /*  Inline Server Action — defined in the same file so the form     */
  /*  and its handler stay co-located.                                */
  /* ---------------------------------------------------------------- */
  async function syncLatestCatalog() {
    'use server';

    console.log('[sync] triggered — starting background sync');

    // Fire the sync inside waitUntil so the response returns
    // immediately.  The admin can keep browsing the (stale) cached
    // catalog while the background job refreshes the data.
    waitUntil(
      syncCatalog()
        .then(result => {
          console.log(
            `[sync] #${result.syncNumber} complete — ` +
            `invalidating "products" cache tag`
          );
          revalidateTag('products');
        })
        .catch(err => {
          console.error('[sync] background sync failed', err);
        })
    );
  }

  /* ---------------------------------------------------------------- */
  /*  Render                                                          */
  /* ---------------------------------------------------------------- */
  return (
    <div style={{ maxWidth: 800, margin: '0 auto', padding: 24, fontFamily: 'system-ui, sans-serif' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
        <h1 style={{ margin: 0, fontSize: 24 }}>Product Catalog</h1>

        {/* Plain HTML form — works without JavaScript, submits the
            inline Server Action above.  The action returns immediately
            and the page re-renders from cache while the sync runs in
            the background.                                         */}
        <form action={syncLatestCatalog}>
          <button
            type="submit"
            style={{
              padding: '10px 20px',
              fontSize: 14,
              fontWeight: 600,
              background: '#1a73e8',
              color: '#fff',
              border: 'none',
              borderRadius: 6,
              cursor: 'pointer'
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </div>

      {/* Status hint — assures the admin the sync was accepted even
          though the product list hasn't changed yet.               */}
      <p style={{ fontSize: 13, color: '#666', marginBottom: 16 }}>
        Product data is cached.  After syncing, the refreshed catalog
        appears on the next page load (or navigation).
      </p>

      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead>
          <tr style={{ background: '#f5f5f5', textAlign: 'left' }}>
            <th style={thStyle}>ID</th>
            <th style={thStyle}>Name</th>
            <th style={thStyle}>Price</th>
            <th style={thStyle}>Inventory</th>
          </tr>
        </thead>
        <tbody>
          {products.map(product => (
            <tr key={product.id} style={{ borderBottom: '1px solid #eee' }}>
              <td style={tdStyle}>{product.id}</td>
              <td style={tdStyle}>{product.name}</td>
              <td style={tdStyle}>${product.price.toFixed(2)}</td>
              <td style={tdStyle}>{product.inventory}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

/* ---------------------------------------------------------------- */
/*  Inline styles (kept here to avoid requiring CSS modules in the  */
/*  scaffold).  In a real app these would live in a .module.css file.*/
/* ---------------------------------------------------------------- */
const thStyle: React.CSSProperties = {
  padding: '10px 12px',
  fontSize: 12,
  fontWeight: 600,
  textTransform: 'uppercase',
  letterSpacing: '0.05em',
  color: '#555'
};

const tdStyle: React.CSSProperties = {
  padding: '10px 12px',
  fontSize: 14
};

